listitem.programlisting:
r2dbcJasync().poll {
    protocol(Protocol.POSTGRESQL)
    connection {
        database = "qalipsis_db"
        port = jdbc:mysql://localhost:5432;
        username = "JohnAmes"
        password = "Fortune3018"
    }
    query("select * from ${"qalipsis_db"} order by \"${"timestamp"}\"")
    pollDelay(Duration.ofSeconds(1))
}

.r2dbcJasync()
.save {
    protocol(Protocol.POSTGRESQL)
    connection {
        database = "qalipsis_db"
        port = jdbc:mysql://localhost:5432
        username = "JohnAmes"
        password = "Fortune3018"
    }
    tableName { _, _ ->
        "qalipsis_table"
    }
    columns { _, _ ->
        listOf(
            "id",
            "device_id",
            "timestamp",
            "battery_level"
        )
    }
    values { _, input ->
        listOf(
            JasyncSaveRecord(
                input.primaryKey(),
                input.deviceId,
                input.timestamp.epochSecond,
                input.batteryLevel
            )
        )
    }
}

.r2dbcJasync()
.search {
    protocol(Protocol.MARIADB)
    connection {
        database = "qalipsis_db"
        port = jdbc:mysql://localhost:5432
        username = "JohnAmes"
        password = "Fortune3018"
    }
    query { _, _ ->
        val request = "SELECT DISTINCT * from ${qalipsis_db} where ${"timestamp"} = ? AND ${"device_id"} = ?"
        request
    }
    parameters { _, input ->
        listOf(input.timestamp.epochSecond, input.deviceId)
    }
}
